mapper.select:
select c.*, d.name as department_name, u.real_name as artist_name from repertoire_info c left join opera_category d on c.department_id = d.id left join sys_user u on c.artist_id = u.id
and c.course_name like concat('%', #{courseName}, '%')
and c.artist_id = #{artistId}
and c.status = #{status}
order by c.id desc

mapper.update:
update repertoire_info
course_name = #{courseName}, course_code = #{courseCode}, department_id = #{departmentId}, artist_id = #{artistId}, credit = #{credit}, course_type = #{courseType}, course_hours = #{courseHours}, course_desc = #{courseDesc}, status = #{status},
where id = #{id}
